Create the following files for a DIAGONAL COMMITMENT MAP canvas:

## 1. src/canvas/types.ts

The canvas is NOT a generic node graph. It is a diagonal commitment map where:
- X-axis = progress toward outcome (left=understanding, right=completion)
- Y-axis = commitment / external side effects (top=low, bottom=high)
- Golden path walks the diagonal from upper-left to lower-right
- Same row right = alternate route at same commitment level
- Same column below = escalation/approval/recovery

```typescript
export interface MapPosition {
  col: number;  // X: progress toward outcome (0 = start)
  row: number;  // Y: commitment level (0 = low commitment)
}

export type ActorKind = 'agent' | 'app' | 'human' | 'subflow';

export interface ContextPack {
  id: string;
  label: string;
  kind: 'document' | 'sop' | 'schema' | 'data_view' | 'memory' | 'retrieval';
  sourceRef?: string;
}

export interface PolicyChip {
  id: string;
  label: string;
  trigger: string;
  action: 'retry' | 'ask_user' | 'escalate' | 'halt' | 'fallback' | 'skip';
  detail?: string;
}

export interface StepCard {
  id: string;
  kind: 'step';
  position: MapPosition;
  objective: string;
  actor: ActorKind;
  actorDetail?: string;
  contextPacks: ContextPack[];
  successContract: {
    outputShape: Record<string, string>;
    doneCondition: string;
  };
  recoveryContract: PolicyChip[];
}

export interface SubflowCard {
  id: string;
  kind: 'subflow';
  position: MapPosition;
  name: string;
  purpose: string;
  inputs: Record<string, string>;
  outputs: Record<string, string>;
  owner?: string;
  sla?: { maxLatencyMs: number; costHint?: string };
  approvalRequired: boolean;
  innerRef: string;
}

export type MapCard = StepCard | SubflowCard;

export type EdgeKind = 'proceeds_to' | 'alternate_route' | 'escalates_to' | 'recovers_via';

export interface MapEdge {
  id: string;
  from: string;
  to: string;
  kind: EdgeKind;
  label?: string;
}

export interface OperatingModel {
  id: string;
  name: string;
  goal: string;
  cards: MapCard[];
  edges: MapEdge[];
}

// Runtime overlay (Phase 5, but define types now)
export interface CardRunState {
  cardId: string;
  status: 'pending' | 'running' | 'complete' | 'failed' | 'awaiting_human';
  confidence?: number;
  latencyMs?: number;
  costUsd?: number;
  docsConsulted: string[];
  humanApprovalUsed: boolean;
  branchReason?: string;
}

// Actor color mapping
export const ACTOR_COLORS: Record<ActorKind, string> = {
  agent: '#58a6ff',
  app: '#3fb950',
  human: '#d29922',
  subflow: '#bc8cff',
};

// Policy action icons
